const row = $input.first().json;

// Пропускаем если Копирайт уже заполнен или ТЗ пустой
if (row['Копирайт'] || !row['ТЗ'] || row['ТЗ'].trim() === '') {
  return [];
}

const url = row['ТЗ'] || '';
const match = url.match(/\/d\/([a-zA-Z0-9-_]+)/);
const docId = match ? match[1] : null;

if (!docId) {
  throw new Error('Не удалось извлечь ID документа из URL: ' + url);
}

return [{ json: { ...row, docId } }];

const item = $input.first().json;
const text = item.content || item.docText || '';

// H1
const h1Match = text.match(/H1[:\s]+([^\n]+)/i);
const h1 = h1Match ? h1Match[1].trim() : (item['H1 (главный ключ)'] || '');

// Объём
const volMatch = text.match(/Рекомендуемый объём[:\s]+([^\n]+)/i);
const volume = volMatch ? volMatch[1].trim() : '~3000 символов';

// Тональность
const toneMatch = text.match(/Тональность[:\s]+([^\n]+)/i);
const tone = toneMatch ? toneMatch[1].trim() : 'Информативный, экспертный';

// LSI-фразы
const lsiSectionMatch = text.match(/LSI-фразы[\s\S]*?\n[^\n]+\n([^\n]+)/i);
const lsiRaw = lsiSectionMatch ? lsiSectionMatch[1] : '';
const lsiPhrases = lsiRaw.split(';').map(s => s.trim()).filter(s => s.length > 2);

// Топ-фразы конкурентов — ищем все строки с паттерном "фраза: N / N -- avg"
const freqTargets = {};
const freqLines = text.matchAll(/^([^\n:]+?):\s*[\d\s\/]+--\s*([\d.]+)\s*$/gm);
for (const m of freqLines) {
  freqTargets[m[1].trim().toLowerCase()] = parseFloat(m[2]);
}

// Форматируем для промпта
const freqTargetsText = Object.entries(freqTargets)
  .map(([phrase, avg]) => phrase + ': max ' + Math.ceil(avg))
  .join('\n');

// Структура страницы
const structStart = text.indexOf('Структура страницы');
const structEnd = text.indexOf('Обязательные блоки');
const structure = (structStart > -1 && structEnd > -1)
  ? text.slice(structStart, structEnd).trim() : '';

// Обязательные блоки
const mandStart = text.indexOf('Обязательные блоки');
const mandEnd = text.indexOf('Чего нет у конкурентов');
const mandatoryBlocks = (mandStart > -1)
  ? text.slice(mandStart, mandEnd > -1 ? mandEnd : mandStart + 800).trim() : '';

// Чего нет у конкурентов
const uniqueStart = text.indexOf('Чего нет у конкурентов');
const uniqueEnd = text.indexOf('Нейроанализ', uniqueStart);
const uniqueBlocks = (uniqueStart > -1)
  ? text.slice(uniqueStart, uniqueEnd > -1 ? uniqueEnd : uniqueStart + 500).trim() : '';

// Нейроанализ
const neuroStart = text.indexOf('Нейроанализ');
const neuroAnalysis = neuroStart > -1 ? text.slice(neuroStart).trim() : '';

return [{
  json: {
    h1,
    volume,
    tone,
    lsiPhrases,
    lsiPhrasesText: lsiPhrases.join('\n'),
    freqTargets,
    freqTargetsText,
    structure,
    mandatoryBlocks,
    uniqueBlocks,
    neuroAnalysis,
    rowNumber: item.row_number || 2,
    docId: item.docId || item.documentId,
    originalH1: item['H1 (главный ключ)'] || h1,
    fullTZ: text
  }
}];

const item = $input.first().json;

// Берём Ключевые из ноды где ещё была строка Sheets
const prevNode = $('Code — Извлекаем ID документа').first().json;
const keysRaw = prevNode['Ключевые'] || '';

const toStringSafe = v => (v == null ? "" : String(v));

const tokenize = s => {
  const m = toStringSafe(s).toLowerCase().match(/\p{L}[\p{L}\p{Nd}-]*/gu);
  return m || [];
};

const ngrams = (tokens, n) => {
  const res = [];
  for (let i = 0; i <= tokens.length - n; i++) {
    res.push(tokens.slice(i, i + n).join(" "));
  }
  return res;
};

const keysArr = toStringSafe(keysRaw)
  .split(/[\n;,]+/)
  .map(s => s.trim())
  .filter(Boolean);

const grams2 = new Set();
const grams3 = new Set();

for (const k of keysArr) {
  const toks = tokenize(k);
  ngrams(toks, 2).forEach(g => grams2.add(g));
  ngrams(toks, 3).forEach(g => grams3.add(g));
}

return [{
  json: {
    ...item,
    keywords: keysArr,
    ngrams2: Array.from(grams2),
    ngrams3: Array.from(grams3),
    // Тащим Нейроанализ тоже — пригодится для Писателя
    neuroAnalysis: prevNode['Нейроанализ'] || '',
  }
}];

const rawEditor = $('Корректор').item.json.output;
const checkerOutput = $('Проверка ТЗ').item.json.output;
const h1 = $('Code — Парсим ТЗ').item.json.h1;
const lsiPhrases = $('Code — Парсим ТЗ').item.json.lsiPhrases || [];

const mdMatch = rawEditor.match(/```markdown\n([\s\S]*?)```/);
let editorOutput = mdMatch ? mdMatch[1].trim() : rawEditor;

// Чистим ссылки и скобки
editorOutput = editorOutput.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1');
editorOutput = editorOutput.replace(/\[([^\]]+)\]/g, '$1');

// Убираем "Символов без пробелов"
editorOutput = editorOutput.replace(/\n\*{0,2}Символов без пробелов[^\n]+\n?/gi, '');

// Убираем служебные хвосты KEYS_USED / QUALITY_SCORE / PLACEHOLDERS
editorOutput = editorOutput.replace(/\n#{3,5}\s*(KEYS_USED|PLACEHOLDERS_REMAINING|QUALITY_SCORE|ПРАВКИ)[^\n]*[\s\S]*?(?=\n#|\n---\n|$)/gi, '');
editorOutput = editorOutput.replace(/\n---\s*$/, '').trim();

const divider = '\n\n' + '═'.repeat(50) + '\nОТЧЁТ ПРОВЕРКИ ТЗ\n' + '═'.repeat(50) + '\n\n';
const fullContent = editorOutput + divider + checkerOutput;

return [{
  json: {
    title: h1,
    content: fullContent,
    editorOutput,
    checkerOutput,
    lsiPhrases,
    rowNumber: $('Code — Парсим ТЗ').item.json.rowNumber,
    originalH1: $('Code — Парсим ТЗ').item.json.originalH1
  }
}];

