const documentId = $('GDoc').item.json.id;
const raw = $('Готовим контент').item.json.editorOutput;

let content = raw;

// Ищем первый H1 — одиночный # не окружённый другими #
const h1Pos = raw.search(/(?<![#])# (?!#)/);
if (h1Pos !== -1) {
  content = raw.slice(h1Pos);
}

// Убираем служебные хвосты
content = content
  .replace(/\nВнесённые правки[\s\S]*/i, '')
  .replace(/\n---\n[\s\S]*?Внесённые правки[\s\S]*/i, '')
  .replace(/\n#{5,}[^\n]*/g, '')
  .replace(/\n-{3,}\n/g, '\n')
  .trim();

const insertRequests = [];
const styleRequests = [];
let idx = 1;

function ins(text) {
  const start = idx;
  insertRequests.push({ insertText: { location: { index: idx }, text } });
  idx += text.length;
  return start;
}

function parseInline(text) {
  let clean = '';
  const boldRanges = [];
  let i = 0;
  while (i < text.length) {
    if (text[i] === '*' && i + 1 < text.length && text[i+1] === '*') {
      const start = clean.length;
      i += 2;
      while (i < text.length && !(text[i] === '*' && i + 1 < text.length && text[i+1] === '*')) {
        clean += text[i++];
      }
      boldRanges.push([start, clean.length]);
      i += 2;
    } else {
      clean += text[i++];
    }
  }
  return { clean, boldRanges };
}

function insLine(text, heading, bullet, numbered) {
  const { clean, boldRanges } = parseInline(text);
  const start = ins(clean + '\n');

  if (heading) {
    styleRequests.push({
      updateParagraphStyle: {
        range: { startIndex: start, endIndex: idx - 1 },
        paragraphStyle: { namedStyleType: heading },
        fields: 'namedStyleType'
      }
    });
  }
  if (bullet) {
    styleRequests.push({
      createParagraphBullets: {
        range: { startIndex: start, endIndex: idx },
        bulletPreset: 'BULLET_DISC_CIRCLE_SQUARE'
      }
    });
  }
  if (numbered) {
    styleRequests.push({
      createParagraphBullets: {
        range: { startIndex: start, endIndex: idx },
        bulletPreset: 'NUMBERED_DECIMAL_ALPHA_ROMAN'
      }
    });
  }
  for (const [bs, be] of boldRanges) {
    styleRequests.push({
      updateTextStyle: {
        range: { startIndex: start + bs, endIndex: start + be },
        textStyle: { bold: true },
        fields: 'bold'
      }
    });
  }
}

for (const line of content.split('\n')) {
  const h4m = line.match(/^#### (.+)/);
  const h3m = line.match(/^### (.+)/);
  const h2m = line.match(/^## (.+)/);
  const h1m = line.match(/^# (.+)/);
  const bm  = line.match(/^[-*] (.+)/);
  const nm  = line.match(/^\d+\. (.+)/);

  if (h4m) { insLine(h4m[1], 'HEADING_4'); continue; }
  if (h3m) { insLine(h3m[1], 'HEADING_3'); continue; }
  if (h2m) { insLine(h2m[1], 'HEADING_2'); continue; }
  if (h1m) { insLine(h1m[1], 'HEADING_1'); continue; }
  if (bm)  { insLine(bm[1], null, true);   continue; }
  if (nm)  { insLine(nm[1], null, false, true); continue; }
  if (line.trim() === '') { ins('\n'); continue; }

  insLine(line);
}

const requests = [...insertRequests, ...styleRequests];
return [{ json: { documentId, requestsJson: JSON.stringify({ requests }) } }];

// Данные компании из Supabase
const supaVal = $('Supabase connect').first().json.value || '';
const companyMatch = supaVal.match(/Название:\s*([^\r\n]+)/);
const addressMatch = supaVal.match(/Адрес:\s*[^,]+,\s*([^,]+)/); // берём город

const companyName = companyMatch ? companyMatch[1].trim() : '';
// Топоним — первое слово после "г." или "г " в адресе
const toponymRaw = addressMatch ? addressMatch[0] : '';
const toponymMatch = toponymRaw.match(/г\.?\s+([А-ЯЁа-яё\-]+)/);
const toponym = toponymMatch ? toponymMatch[1].trim() : '';

// Ключи и LSI
const keywords = $('N-граммы').first().json.keywords || [];
const lsiPhrases = $('Code — Парсим ТЗ').first().json.lsiPhrases || [];

// Стоп-слова (хардкод — редко меняются)
const stopWords = [
  'надёжный', 'качественный', 'лучший', 'уникальный',
  'эффективный', 'доступный', 'профессиональный', 'современный'
];

// Собираем все фразы в один список для Gemini
const allPhrases = {
  keywords: keywords,
  lsi: lsiPhrases,
  toponym: toponym ? [toponym] : [],
  company: companyName ? [companyName] : [],
  stopWords: stopWords
};

// documentId и docUrl для следующих нод
const documentId = $('GDoc').first().json.id;
const docUrl = 'https://docs.google.com/document/d/' + documentId + '/edit';
const rowNumber = $('Code — Парсим ТЗ').first().json.rowNumber;
const originalH1 = $('Code — Парсим ТЗ').first().json.originalH1;

return [{
  json: {
    allPhrases,
    phrasesJson: JSON.stringify(allPhrases),
    documentId,
    docUrl,
    rowNumber,
    originalH1,
    companyName,
    toponym
  }
}];

const allPhrases = $json.allPhrases;
const editorOutput = $('Готовим контент').item.json.editorOutput;

const prompt = "Вот текст статьи и список фраз по категориям.\n\n" +
  "Найди в тексте все вхождения каждой фразы с учётом морфологии и синонимов. " +
  "Верни ТОЛЬКО валидный JSON без markdown и пояснений:\n" +
  "{\"keywords\": [...], \"lsi\": [...], \"toponym\": [...], \"company\": [...], \"stopWords\": [...]}\n\n" +
  "Каждый массив — только те строки которые реально есть в тексте (в той форме как они написаны).\n\n" +
  "ФРАЗЫ ПО КАТЕГОРИЯМ:\n" +
  JSON.stringify(allPhrases) +
  "\n\nТЕКСТ СТАТЬИ:\n" +
  editorOutput;

const body = {
  model: "google/gemini-2.5-flash",
  max_tokens: 4000,
  messages: [{ role: "user", content: prompt }]
};

return [{
  json: {
    documentId: $json.documentId,
    docUrl: $json.docUrl,
    rowNumber: $json.rowNumber,
    originalH1: $json.originalH1,
    allPhrases: allPhrases,
    requestBody: JSON.stringify(body)
  }
}];

const raw = $json.choices[0].message.content;

// Убираем markdown-обёртку
const match = raw.match(/```json\n([\s\S]*?)```/);
const jsonStr = match ? match[1].trim() : raw.trim();

let found;
try {
  found = JSON.parse(jsonStr);
} catch(e) {
  throw new Error('Не удалось распарсить ответ Gemini: ' + jsonStr.substring(0, 200));
}

// Тащим метаданные из предыдущей ноды
const prev = $('Готовим запрос Gemini').item.json;

return [{
  json: {
    found,
    documentId: prev.documentId,
    docUrl: prev.docUrl,
    rowNumber: prev.rowNumber,
    originalH1: prev.originalH1
  }
}];

const docContent = $input.first().json.body.content;
const found = $('Парсим ответ Gemini').item.json.found;
const prev = $('Парсим ответ Gemini').item.json;

// Цвета по категориям
const colors = {
  keywords:  { red: 1,     green: 0.949, blue: 0.4   }, // жёлтый
  lsi:       { red: 0.714, green: 0.914, blue: 0.655  }, // зелёный
  toponym:   { red: 0.643, green: 0.855, blue: 0.957  }, // голубой
  company:   { red: 1,     green: 0.753, blue: 0.4    }, // оранжевый
  stopWords: { red: 0.957, green: 0.522, blue: 0.518  }  // красный
};

// Собираем все textRuns с абсолютными индексами
const textRuns = [];
for (const block of docContent) {
  if (!block.paragraph) continue;
  for (const el of block.paragraph.elements) {
    if (el.textRun && el.textRun.content) {
      textRuns.push({
        start: el.startIndex,
        end: el.endIndex,
        content: el.textRun.content
      });
    }
  }
}

const requests = [];
const counts = {}; // { phrase: { category, count } }

// Ищем каждую фразу по категориям
for (const [category, phrases] of Object.entries(found)) {
  const color = colors[category];
  if (!color) continue;

  for (const phrase of phrases) {
    if (!phrase || phrase.length < 2) continue;
    const lowerPhrase = phrase.toLowerCase();
    let totalCount = 0;

    for (const run of textRuns) {
      const lowerContent = run.content.toLowerCase();
      let pos = 0;
      while (true) {
        const idx = lowerContent.indexOf(lowerPhrase, pos);
        if (idx === -1) break;

        const absStart = run.start + idx;
        const absEnd = absStart + phrase.length;

        requests.push({
          updateTextStyle: {
            range: { startIndex: absStart, endIndex: absEnd },
            textStyle: {
              backgroundColor: {
                color: { rgbColor: color }
              }
            },
            fields: 'backgroundColor'
          }
        });

        totalCount++;
        pos = idx + lowerPhrase.length;
      }
    }

    if (totalCount > 0) {
      counts[phrase] = { category, count: totalCount };
    }
  }
}

return [{
  json: {
    documentId: prev.documentId,
    docUrl: prev.docUrl,
    rowNumber: prev.rowNumber,
    originalH1: prev.originalH1,
    requestsJson: JSON.stringify({ requests }),
    counts,
    totalHighlights: requests.length
  }
}];

const text = $('Редактор').item.json.output;
const freqTargets = $('N-граммы').item.json.freqTargets;

const overLimit = [];
const stats = {};

for (const [phrase, limit] of Object.entries(freqTargets)) {
  const escaped = phrase.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const regex = new RegExp(escaped, 'gi');
  const matches = text.match(regex);
  const count = matches ? matches.length : 0;
  const max = Math.ceil(limit);
  stats[phrase] = { count, max };
  if (count > max) {
    overLimit.push(`"${phrase}": найдено ${count}, лимит ${max}, убрать ${count - max}`);
  }
}

const needFix = overLimit.length > 0;

// Название компании из Supabase
const supaVal = $('Supabase connect').item.json.value || '';
const companyMatch = supaVal.match(/Название:\s*([^\r\n]+)/);
if (companyMatch) {
  const companyName = companyMatch[1].trim();
  const companyRegex = new RegExp(companyName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g');
  const companyCount = (text.match(companyRegex) || []).length;
  const companyMax = 5;
  stats[companyName] = { count: companyCount, max: companyMax };
  if (companyCount > companyMax) {
    overLimit.push(`"${companyName}": найдено ${companyCount}, лимит ${companyMax}, убрать ${companyCount - companyMax}`);
  }
}

return [{
  json: {
    text,
    stats,
    overLimit,
    needFix,
    overLimitText: overLimit.join('\n'),
    documentId: $('N-граммы').item.json.docId,
    rowNumber: $('N-граммы').item.json.rowNumber,
    originalH1: $('N-граммы').item.json.originalH1
  }
}];

const text = $('Готовим контент').item.json.editorOutput.toLowerCase();
const documentId = $('Подсветка').item.json.documentId;
const docUrl = $('Подсветка').item.json.docUrl;
const rowNumber = $('Подсветка').item.json.rowNumber;
const originalH1 = $('Подсветка').item.json.originalH1;

// Пересчитываем из финального текста, а не из stats Редактора
const statsOld = $('Проверка частот').item.json.stats || {};
const freqRows = Object.entries(statsOld).map(([phrase, data]) => {
  const escaped = phrase.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const count = (text.match(new RegExp(escaped, 'gi')) || []).length;
  return {
    label: phrase,
    count: String(count),
    limit: String(data.max),
    ok: count <= data.max
  };
});

const lsiPhrases = $('Code — Парсим ТЗ').item.json.lsiPhrases || [];
const lsiRows = lsiPhrases.map(phrase => ({
  label: phrase,
  ok: text.includes(phrase.toLowerCase())
}));

const structure = $('Code — Парсим ТЗ').item.json.structure || '';
const mandatoryBlocks = $('Code — Парсим ТЗ').item.json.mandatoryBlocks || '';
const thesisLines = (structure + '\n' + mandatoryBlocks)
  .split('\n')
  .map(l => l.replace(/^[-*•\d.]+\s*/, '').trim())
  .filter(l => 
    l.length > 15 &&
    !/^(структура|обязательные|блок|раздел)/i.test(l) &&
    !/\d{1,2}:\d{2}/.test(l) &&
    !/\d+\s*(руб|р\.|₽)/i.test(l) &&
    !/~\s*\d/.test(l) &&
    !/от\s+\d/i.test(l) &&
    !/siemens|philips|ge |canon|hitachi/i.test(l)
  );

const thesisRows = thesisLines.map(thesis => {
  const keywords = thesis.toLowerCase().match(/[а-яё]{5,}/g) || [];
  const covered = keywords.length > 0 && keywords.some(kw => text.includes(kw));
  return { label: thesis, ok: covered };
});

return [{ json: { documentId, docUrl, rowNumber, originalH1, freqRows, lsiRows, thesisRows } }];

const docContent = $input.first().json.body.content;
const data = $('Отчет').item.json;

let endIndex = 1;
for (const block of docContent) {
  if (block.endIndex) endIndex = block.endIndex;
}
const idx = Math.max(endIndex - 1, 1);

const header = '\n\n' + '═'.repeat(50) + '\nАНАЛИЗ СООТВЕТСТВИЯ ТЗ\n' + '═'.repeat(50) + '\n\nТОП-ФРАЗЫ (ЧАСТОТНОСТЬ)\n';
const freqRowCount = data.freqRows.length + 1;

const requests = [
  { insertText: { location: { index: idx }, text: header } },
  { insertTable: { rows: freqRowCount, columns: 3, location: { index: idx + header.length } } }
];

return [{ json: {
  documentId: data.documentId, docUrl: data.docUrl,
  rowNumber: data.rowNumber, originalH1: data.originalH1,
  requestsJson: JSON.stringify({ requests })
}}];

const docContent = $input.first().json.body.content;
const data = $('Отчет').item.json;

let endIndex = 1;
for (const block of docContent) {
  if (block.endIndex) endIndex = block.endIndex;
}
const idx = Math.max(endIndex - 1, 1);

const header = '\n\nLSI-ФРАЗЫ\n';
const lsiRowCount = data.lsiRows.length + 1;

const requests = [
  { insertText: { location: { index: idx }, text: header } },
  { insertTable: { rows: lsiRowCount, columns: 2, location: { index: idx + header.length } } },
  { insertText: { endOfSegmentLocation: { segmentId: '' }, text: '\n\n' } }
];

return [{ json: {
  documentId: data.documentId, docUrl: data.docUrl,
  rowNumber: data.rowNumber, originalH1: data.originalH1,
  requestsJson: JSON.stringify({ requests })
}}];

const docContent = $input.first().json.body.content;
const data = $('Отчет').item.json;

const tables = docContent.filter(b => b.table);
const freqTable = tables[tables.length - 2];
const lsiTable  = tables[tables.length - 1];

const sections = [
  {
    tableData: freqTable,
    headers: ['Фраза', 'Вхождений', 'Лимит'],
    rows: data.freqRows,
    cols: 3,
    getCells: r => [r.label, r.count, r.limit],
    isOk: r => r.ok
  },
  {
    tableData: lsiTable,
    headers: ['Фраза', 'Статус'],
    rows: data.lsiRows,
    cols: 2,
    getCells: r => [r.label, r.ok ? 'есть ✅' : 'нет ❌'],
    isOk: r => r.ok
  }
];

const allCellInserts = [];
const colorMeta = [];

for (const section of sections) {
  if (!section.tableData) continue;
  const tableStartIndex = section.tableData.startIndex;
  const tableRows = section.tableData.table.tableRows;

  for (let c = 0; c < section.cols; c++) {
    const cell = tableRows[0].tableCells[c];
    allCellInserts.push({ index: cell.content[0].startIndex, text: section.headers[c], rowIndex: 0, colIndex: c, isHeader: true, ok: true, tableStartIndex });
  }
  for (let r = 0; r < section.rows.length; r++) {
    const row = section.rows[r];
    const cells = section.getCells(row);
    const ok = section.isOk(row);
    for (let c = 0; c < section.cols; c++) {
      const cell = tableRows[r + 1].tableCells[c];
      allCellInserts.push({ index: cell.content[0].startIndex, text: cells[c], rowIndex: r + 1, colIndex: c, isHeader: false, ok, tableStartIndex });
    }
  }
}

// Глобальная сортировка — все ячейки обеих таблиц вместе
allCellInserts.sort((a, b) => b.index - a.index);

const insertRequests = [];
for (const ci of allCellInserts) {
  insertRequests.push({ insertText: { location: { index: ci.index }, text: ci.text } });
  colorMeta.push({ rowIndex: ci.rowIndex, colIndex: ci.colIndex, isHeader: ci.isHeader, ok: ci.ok, tableStartIndex: ci.tableStartIndex });
}

const thesisText = '\n\nСТРУКТУРА И ТЕЗИСЫ:\n' +
  data.thesisRows.map(r => `${r.ok ? '✅' : '❌'} ${r.label}`).join('\n');

return [{ json: {
  documentId: data.documentId,
  requestsJson: JSON.stringify({ requests: insertRequests }),
  colorMeta: JSON.stringify(colorMeta),
  thesisText,
  docUrl: data.docUrl,
  rowNumber: data.rowNumber,
  originalH1: data.originalH1
}}];

