  requestsJson: JSON.stringify({ requests: [{
    insertText: {
      endOfSegmentLocation: { segmentId: '' },
      text: prev.thesisText
    }
  }]}),
  colorMeta: prev.colorMeta,
  docUrl: prev.docUrl,
  rowNumber: prev.rowNumber,
  originalH1: prev.originalH1
}}];
